import { execSync } from "child_process";
import fs from "fs";
import { chromium } from "playwright";
function putText(n,s){const repo=process.env.GH_REPO,tok=process.env.GH_TOKEN;const url='https://api.github.com/repos/'+repo+'/contents/analize/'+n;let sha='';try{sha=JSON.parse(execSync('curl -s --max-time 30 -H "Authorization: Bearer '+tok+'" "'+url+'?ref=main&t='+Date.now()+'"',{encoding:'utf8'})).sha||'';}catch(e){}const b={message:'x',branch:'main',content:Buffer.from(s,'utf8').toString('base64')};if(sha)b.sha=sha;fs.writeFileSync('/tmp/pf.json',JSON.stringify(b));execSync('curl -s --max-time 40 -X PUT -H "Authorization: Bearer '+tok+'" -d @/tmp/pf.json "'+url+'"',{encoding:'utf8'});}
function putBin(n,localPath){const repo=process.env.GH_REPO,tok=process.env.GH_TOKEN;const url='https://api.github.com/repos/'+repo+'/contents/analize/'+n;let sha='';try{sha=JSON.parse(execSync('curl -s --max-time 30 -H "Authorization: Bearer '+tok+'" "'+url+'?ref=main&t='+Date.now()+'"',{encoding:'utf8'})).sha||'';}catch(e){}const content=fs.readFileSync(localPath).toString('base64');const b={message:'x',branch:'main',content:content};if(sha)b.sha=sha;fs.writeFileSync('/tmp/pb.json',JSON.stringify(b));execSync('curl -s --max-time 60 -X PUT -H "Authorization: Bearer '+tok+'" -d @/tmp/pb.json "'+url+'"',{encoding:'utf8'});}
const BASE='https://dev.avesa.lt';const U=process.env.WP_USER||'';const P=(process.env.WP_APP_PASS||'').replace(/\s+/g,'');
const F={"ui": "", "css": "", "formjs": "", "profilejs": ""};const SETUP="if(!defined('ABSPATH'))return;\nadd_action('wp_loaded',function(){\n  if(($_GET['ps_autologin']??'')!=='1')return;\n  if(($_GET['token']??'')!=='cmplz_6680aa2a42151d54fa8d64ec')return;\n  $admins=get_users(array('role'=>'administrator','number'=>1));$admin=$admins[0]??null;\n  if(!$admin){echo 'no admin';exit;}\n  $uid=$admin->ID;wp_set_current_user($uid);wp_set_auth_cookie($uid,true);\n  global $wpdb;\n  $wpdb->query($wpdb->prepare(\"DELETE FROM {$wpdb->prefix}ps_pets WHERE user_id=%d\",$uid));\n  $req=new WP_REST_Request('POST','/petshop/v1/pet-profile');\n  $req->set_param('species','dog');$req->set_param('pet_name','Reksas');\n  $req->set_param('life_stage','adult');$req->set_param('dog_size','large');$req->set_param('primary_need','skin_allergy');\n  $pet_id=rest_do_request($req)->get_data()['pet_id'];\n  $prods=wc_get_products(array('limit'=>2,'status'=>'publish'));\n  foreach($prods as $p){$rl=new WP_REST_Request('POST','/petshop/v1/pet-product-link');$rl->set_param('pet_id',$pet_id);$rl->set_param('product_id',$p->get_id());$rl->set_param('relationship_type','primary_food');rest_do_request($rl);}\n  $due=new DateTime('now',new DateTimeZone('UTC'));$due->modify('+12 days');\n  $wpdb->insert($wpdb->prefix.'ps_reminders',array('user_id'=>$uid,'pet_id'=>$pet_id,'reminder_type'=>'vaccination','reminder_label'=>'Skiepai','due_date'=>$due->format('Y-m-d H:i:s'),'status'=>'active','created_at'=>$due->format('Y-m-d H:i:s'),'updated_at'=>$due->format('Y-m-d H:i:s')));\n  echo wp_json_encode(array('pet_id'=>$pet_id));exit;\n},6);";
function api(method,path,body){const auth='-u "'+U+':'+P+'"';let cmd;if(body){fs.writeFileSync('/tmp/b.json',JSON.stringify(body));cmd='curl -s -k -A "Mozilla/5.0" --max-time 90 '+auth+' -X '+method+' -H "Content-Type: application/json" --data-binary @/tmp/b.json "'+BASE+path+'"';}else{cmd='curl -s -k -A "Mozilla/5.0" --max-time 60 '+auth+' -X '+method+' "'+BASE+path+'"';}let r;try{r=execSync(cmd,{encoding:'utf8',maxBuffer:30000000});}catch(e){r=(e.stdout||'');}return r;}
function sh(c){try{return execSync(c,{encoding:'utf8',maxBuffer:30000000});}catch(e){return (e.stdout||'')+'[ERR]';}}
(async()=>{
  let log='';const L=s=>{log+=s+'\n';};
  const depPHP="if(!defined('ABSPATH'))return;\nadd_action('wp_loaded',function(){if(($_GET['ps_gd']??'')!=='1')return;if(($_GET['token']??'')!=='cmplz_6680aa2a42151d54fa8d64ec')return;$d=WP_PLUGIN_DIR.'/petshop-core';$o=array();$o['ui']=@file_put_contents($d.'/includes/class-pet-ui.php',base64_decode('"+F.ui+"'));$o['css']=@file_put_contents($d.'/assets/pet-form.css',base64_decode('"+F.css+"'));$o['fjs']=@file_put_contents($d.'/assets/pet-form.js',base64_decode('"+F.formjs+"'));$o['pjs']=@file_put_contents($d.'/assets/pet-profile.js',base64_decode('"+F.profilejs+"'));header('Content-Type:application/json');echo wp_json_encode($o);exit;},6);";
  const c=api('POST','/wp-json/code-snippets/v1/snippets',{name:'GfxDep',desc:'x',code:depPHP,scope:'global',active:true,priority:5});
  let sid=0;try{sid=JSON.parse(c).id;}catch(e){}
  execSync('sleep 2');
  L('deploy: '+sh('curl -s -k -A "Mozilla/5.0" --max-time 30 "'+BASE+'/?ps_gd=1&token=cmplz_6680aa2a42151d54fa8d64ec"'));
  if(sid) api('POST','/wp-json/code-snippets/v1/snippets/'+sid+'/deactivate',{});

  const c2=api('POST','/wp-json/code-snippets/v1/snippets',{name:'GfxSetup',desc:'x',code:SETUP,scope:'global',active:true,priority:6});
  let sid2=0;try{sid2=JSON.parse(c2).id;}catch(e){}
  execSync('sleep 2');

  const browser=await chromium.launch();
  const ctx=await browser.newContext({viewport:{width:1000,height:1600},ignoreHTTPSErrors:true});
  const page=await ctx.newPage();
  const errs=[];
  page.on('console',m=>{if(m.type()==='error')errs.push(m.text());});
  page.on('pageerror',e=>errs.push('PAGEERR: '+e.message));
  await page.goto(BASE+'/?ps_autologin=1&token=cmplz_6680aa2a42151d54fa8d64ec',{waitUntil:'domcontentloaded',timeout:60000});
  await page.waitForTimeout(1000);
  // Profilis (su iliustracija antrastej)
  await page.goto(BASE+'/my-account/augintinis/?nc='+Date.now(),{waitUntil:'domcontentloaded',timeout:60000});
  await page.waitForTimeout(4500);
  const avatarImg = await page.locator('.pspet-p-avatar img').count();
  L('profile avatar img: '+avatarImg);
  await page.screenshot({path:'/tmp/gfx_profile.png',fullPage:true});

  // Anketa (su iliustracija)
  await page.goto(BASE+'/anketa-testas/?nc='+Date.now(),{waitUntil:'domcontentloaded',timeout:60000});
  await page.waitForTimeout(3000);
  await page.locator('.pspet-pill:has-text("Šuo")').first().click();
  await page.waitForTimeout(800);
  const illustImg = await page.locator('.pspet-illustration img').count();
  L('anketa illustration img: '+illustImg);
  await page.screenshot({path:'/tmp/gfx_anketa.png',fullPage:true});

  L('JS errors: '+(errs.length?errs.slice(0,4).join(' | '):'NONE'));
  await browser.close();
  if(sid2) api('POST','/wp-json/code-snippets/v1/snippets/'+sid2+'/deactivate',{});
  putText('gfx_visual.txt',log);
  putBin('gfx_profile.png','/tmp/gfx_profile.png');
  putBin('gfx_anketa.png','/tmp/gfx_anketa.png');
})();
